            print(f"Kampyootar sistam chal raha hai... {i+1} second")
            time.sleep(1)
        print("Kampyootar sistam chal gaya hai!")

    def bandhna(self):
        print("Kampyootar sistam bandh raha hai...")
        self.sandesh = "Kampyootar sistam bandh gaya hai!"

    def dikhao(self):
        print(f"Kampyootar sistam ka sandesh: {self.sandesh}")

def main():
    kampyootar = KampyootarSistam()
    while True:
        print("\nKampyootar sistam menu:")
        print("1. Kraish")
        print("2. Chalana")
        print("3. Bandhna")
        print("4. Dikhao")
        print("5. Nikalna")
